-- Reservas de cupones/plataformas → PARTNER
UPDATE reservations SET channel = 'PARTNER' WHERE channel = 'groupon' OR origin_source = 'coupon_redemption';

-- Reservas del TPV → TPV_FISICO
UPDATE reservations SET channel = 'TPV_FISICO' WHERE channel = 'tpv' AND origin_source IS NULL;

-- Reservas web directas (checkout online) → ONLINE_DIRECTO
UPDATE reservations SET channel = 'ONLINE_DIRECTO' WHERE channel = 'web';

-- Reservas creadas por el equipo CRM (email, teléfono, crm, otro) → ONLINE_ASISTIDO
UPDATE reservations SET channel = 'ONLINE_ASISTIDO' WHERE channel IN ('crm', 'email', 'telefono', 'otro');

-- Reservas sin canal asignado que tienen status=paid y no son TPV ni partner → ONLINE_ASISTIDO
UPDATE reservations SET channel = 'ONLINE_ASISTIDO' WHERE (channel IS NULL OR channel = '') AND status = 'paid';

SELECT channel, COUNT(*) as cnt FROM reservations GROUP BY channel ORDER BY cnt DESC;

